const PROGRESS_TICKS=10;function randomNormal(){let n=0,s=0;for(;n===0;)n=Math.random();for(;s===0;)s=Math.random();return Math.sqrt(-2*Math.log(n))*Math.cos(2*Math.PI*s)}function postProgress(n,s,M){M<=0||n>0&&n%M===0&&self.postMessage({progress:n/s})}function extractPercentilePaths(n,s,M,e){const o=new Array(M);let m=0;for(let a=0;a<M;a++){const v=n[a*s+(s-1)];o[a]={index:a,value:v},v>e&&m++}o.sort((a,v)=>a.value-v.value);function l(a){const v=o[Math.floor(M*a)].index,w=new Float32Array(s);for(let g=0;g<s;g++)w[g]=n[v*s+g];return w}return{percentiles:{p05:l(.05),p10:l(.1),p25:l(.25),p45:l(.45),p50:l(.5),p55:l(.55),p75:l(.75),p90:l(.9),p95:l(.95)},pAboveSpot:m/M}}function simulateOU(n,s,M,e,o,m,l,a,v,w,g){const x=1/(252*(v||1)),f=typeof l=="number"&&l>0?l:n*Math.exp(s),u=new Float32Array(o*e),q=M<=1e-8,y=Math.max(1,Math.floor(o/10)),A=w??.1,I=g??.85,j=M*M*x,z=j*(1-A-I);if(a&&!q){const T=o>>1;for(let c=0;c<T;c++){const i=c*2*e,h=(c*2+1)*e;let t=n,r=n,d=j;u[i]=t,u[h]=r;for(let p=1;p<e;p++){const S=randomNormal(),b=Math.sqrt(d);t+=m*(f-t)*x+b*t*S,r+=m*(f-r)*x+b*r*-S,u[i+p]=Math.max(0,t),u[h+p]=Math.max(0,r),d=Math.max(z+(A*S*S+I)*d,1e-10)}postProgress(c*2,o,y)}if(o&1){const c=(o-1)*e;let i=n,h=j;u[c]=i;for(let t=1;t<e;t++){const r=randomNormal();i+=m*(f-i)*x+Math.sqrt(h)*i*r,u[c+t]=Math.max(0,i),h=Math.max(z+(A*r*r+I)*h,1e-10)}}}else for(let T=0;T<o;T++){let c=n,i=j;u[T*e]=c;for(let h=1;h<e;h++){if(q)c+=m*(f-c)*x;else{const t=randomNormal();c+=m*(f-c)*x+Math.sqrt(i)*c*t,i=Math.max(z+(A*t*t+I)*i,1e-10)}u[T*e+h]=Math.max(0,c)}postProgress(T,o,y)}return extractPercentilePaths(u,e,o,n)}function simulateGBMJump(n,s,M,e,o,m,l,a,v,w,g){const x=1/(252*(v||1)),f=new Float32Array(o*e),u=M<=1e-8,q=Math.max(1,Math.floor(o/10)),y=typeof l=="number"?l:0,A=u?0:.07,I=u?0:m*(Math.exp(y+.5*A*A)-1),j=(s-I)*x,z=w??.1,T=g??.85,c=M*M*x,i=c*(1-z-T);if(a&&!u){const h=o>>1;for(let t=0;t<h;t++){const r=t*2*e,d=(t*2+1)*e;let p=n,S=n,b=c;f[r]=p,f[d]=S;for(let R=1;R<e;R++){let G=1,O=1;Math.random()<m*x&&(G=Math.exp(randomNormal()*A+y)),Math.random()<m*x&&(O=Math.exp(randomNormal()*A+y));const V=randomNormal(),B=.5*b,F=Math.sqrt(b);p=p*Math.exp(j-B+F*V)*G,S=S*Math.exp(j-B+F*-V)*O,f[r+R]=Math.max(0,p),f[d+R]=Math.max(0,S),b=Math.max(i+(z*V*V+T)*b,1e-10)}postProgress(t*2,o,q)}if(o&1){const t=(o-1)*e;let r=n,d=c;f[t]=r;for(let p=1;p<e;p++){let S=1;Math.random()<m*x&&(S=Math.exp(randomNormal()*A+y));const b=randomNormal();r=r*Math.exp(j-.5*d+Math.sqrt(d)*b)*S,f[t+p]=Math.max(0,r),d=Math.max(i+(z*b*b+T)*d,1e-10)}}}else for(let h=0;h<o;h++){let t=n,r=c;f[h*e]=t;for(let d=1;d<e;d++){if(u)t=t*Math.exp(j);else{let p=1;Math.random()<m*x&&(p=Math.exp(randomNormal()*A+y));const S=randomNormal();t=t*Math.exp(j-.5*r+Math.sqrt(r)*S)*p,r=Math.max(i+(z*S*S+T)*r,1e-10)}f[h*e+d]=Math.max(0,t)}postProgress(h,o,q)}return extractPercentilePaths(f,e,o,n)}self.onmessage=function(n){const{initialPrice:s,drift:M,volatility:e,steps:o,paths:m,physicsType:l,physicsParams:a,antithetic:v,intradaySteps:w}=n.data;let g;const x=Math.max(1,w||1),f=a?.garchAlpha??.1,u=a?.garchBeta??.85;try{if(l==="Ornstein-Uhlenbeck"){const q=a?.reversionSpeedTheta||.15,y=typeof a?.longTermMean=="number"?a.longTermMean:null;g=simulateOU(s,M,e,o,m,q,y,!!v,x,f,u)}else if(l==="Geometric Brownian Motion + Jump Diffusion"){const q=a?.jumpFrequencyLambda||4,y=typeof a?.jumpMu=="number"?a.jumpMu:0;g=simulateGBMJump(s,M,e,o,m,q,y,!!v,x,f,u)}else{self.postMessage({error:"Unknown physicsType: "+l});return}self.postMessage({percentiles:g.percentiles,pAboveSpot:g.pAboveSpot})}catch(q){self.postMessage({error:q.message})}};
